import {
  ImageCropper as ImageCropperPrimitive,
  useImageCropper,
  useImageCropperContext,
} from '@ark-ui/react/image-cropper';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './ImageCropper.module.css';

const ImageCropperRoot = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Root>,
  ComponentProps<typeof ImageCropperPrimitive.Root>
>(function ImageCropperRoot({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Root
      ref={ref}
      data-slot="image-cropper-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperRootProvider = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.RootProvider>,
  ComponentProps<typeof ImageCropperPrimitive.RootProvider>
>(function ImageCropperRootProvider({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.RootProvider
      ref={ref}
      data-slot="image-cropper-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperViewport = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Viewport>,
  ComponentProps<typeof ImageCropperPrimitive.Viewport>
>(function ImageCropperViewport({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Viewport
      ref={ref}
      data-slot="image-cropper-viewport"
      className={clsx(styles.viewport, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperImage = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Image>,
  ComponentProps<typeof ImageCropperPrimitive.Image>
>(function ImageCropperImage({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Image
      ref={ref}
      data-slot="image-cropper-image"
      className={clsx(styles.image, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperSelection = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Selection>,
  ComponentProps<typeof ImageCropperPrimitive.Selection>
>(function ImageCropperSelection({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Selection
      ref={ref}
      data-slot="image-cropper-selection"
      className={clsx(styles.selection, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperGrid = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Grid>,
  ComponentProps<typeof ImageCropperPrimitive.Grid>
>(function ImageCropperGrid({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Grid
      ref={ref}
      data-slot="image-cropper-grid"
      className={clsx(styles.grid, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperHandle = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Handle>,
  ComponentProps<typeof ImageCropperPrimitive.Handle>
>(function ImageCropperHandle({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Handle
      ref={ref}
      data-slot="image-cropper-handle"
      className={clsx(styles.handle, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperCropArea = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Selection>,
  ComponentProps<typeof ImageCropperPrimitive.Selection> & {
    gridClassName?: string;
    handleClassName?: string;
  }
>(function ImageCropperCropArea({ gridClassName, handleClassName, ...props }, ref) {
  return (
    <ImageCropperSelection ref={ref} {...props}>
      <ImageCropperGrid axis="horizontal" className={gridClassName} />
      <ImageCropperGrid axis="vertical" className={gridClassName} />
      {ImageCropperPrimitive.handles.map((position) => (
        <ImageCropperHandle key={position} position={position} className={handleClassName} />
      ))}
    </ImageCropperSelection>
  );
});

const ImageCropper = Object.assign(ImageCropperRoot, {
  Root: ImageCropperRoot,
  RootProvider: ImageCropperRootProvider,
  Context: ImageCropperPrimitive.Context,
  Viewport: ImageCropperViewport,
  Image: ImageCropperImage,
  Selection: ImageCropperSelection,
  Grid: ImageCropperGrid,
  Handle: ImageCropperHandle,
  CropArea: ImageCropperCropArea,
  handles: ImageCropperPrimitive.handles,
});

export { ImageCropper, useImageCropper, useImageCropperContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: grid;
    width: var(--moduix-image-cropper-width, 32rem);
    max-width: var(--moduix-image-cropper-max-width, 100%);
    gap: var(--moduix-image-cropper-gap, var(--moduix-spacing-3));
    color: var(--moduix-image-cropper-color, var(--moduix-color-foreground));

    &[data-dragging],
    &[data-panning] {
      cursor: grabbing;
    }
  }

  .viewport {
    box-sizing: border-box;
    width: 100%;
    height: var(
      --moduix-image-cropper-viewport-height,
      var(--moduix-image-cropper-viewport-min-height, 20rem)
    );
    overflow: hidden;
    border: var(--moduix-image-cropper-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-image-cropper-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-image-cropper-radius, var(--moduix-radius-lg));
    background:
      linear-gradient(
          45deg,
          var(
              --moduix-image-cropper-checker-color,
              color-mix(in oklab, var(--moduix-color-muted) 72%, transparent)
            )
            25%,
          transparent 25%
        )
        0 0 / var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4))
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)),
      linear-gradient(
          45deg,
          transparent 75%,
          var(
              --moduix-image-cropper-checker-color,
              color-mix(in oklab, var(--moduix-color-muted) 72%, transparent)
            )
            75%
        )
        0 0 / var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4))
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)),
      linear-gradient(
          45deg,
          transparent 75%,
          var(
              --moduix-image-cropper-checker-color,
              color-mix(in oklab, var(--moduix-color-muted) 72%, transparent)
            )
            75%
        )
        calc(var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)) / -2)
        calc(var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)) / -2) /
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4))
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)),
      linear-gradient(
          45deg,
          var(
              --moduix-image-cropper-checker-color,
              color-mix(in oklab, var(--moduix-color-muted) 72%, transparent)
            )
            25%,
          var(--moduix-image-cropper-viewport-bg, var(--moduix-color-background)) 25%
        )
        calc(var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)) / -2)
        calc(var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4)) / -2) /
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4))
        var(--moduix-image-cropper-checker-size, var(--moduix-spacing-4));
    box-shadow: var(--moduix-image-cropper-shadow, none);

    &[data-disabled] {
      cursor: default;
    }
  }

  .image {
    position: absolute;
    inset: 0;
    display: block;
    width: 100%;
    height: 100%;
    object-fit: contain;
    transform-origin: center;
    backface-visibility: hidden;
  }

  .selection {
    box-sizing: content-box;
    border: var(--moduix-image-cropper-selection-border-width, var(--moduix-border-width-md)) solid
      var(--moduix-image-cropper-selection-border-color, var(--moduix-color-primary));
    border-radius: var(--moduix-image-cropper-selection-radius, var(--moduix-radius-md));
    box-shadow:
      0 0 0 9999px var(--moduix-image-cropper-selection-overlay-bg, rgb(0 0 0 / 45%)),
      inset 0 0 0
        var(--moduix-image-cropper-selection-inner-border-width, var(--moduix-border-width-sm))
        var(--moduix-image-cropper-selection-inner-border-color, rgb(255 255 255 / 64%));
    outline: 0;
    cursor: grab;
    transition:
      border-color var(--moduix-image-cropper-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-image-cropper-transition, var(--moduix-transition-default));

    &[data-shape='circle'] {
      border-radius: var(--moduix-image-cropper-selection-circle-radius, var(--moduix-radius-full));
    }

    &:focus-visible {
      box-shadow:
        0 0 0 9999px var(--moduix-image-cropper-selection-overlay-bg, rgb(0 0 0 / 45%)),
        inset 0 0 0
          var(--moduix-image-cropper-selection-inner-border-width, var(--moduix-border-width-sm))
          var(--moduix-image-cropper-selection-inner-border-color, rgb(255 255 255 / 64%)),
        0 0 0
          var(
            --moduix-image-cropper-focus-ring-width,
            var(--moduix-focus-ring-width, var(--moduix-border-width-md))
          )
          var(--moduix-image-cropper-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-dragging] {
      cursor: grabbing;
    }

    &[data-disabled] {
      cursor: default;
    }
  }

  .grid {
    pointer-events: none;

    &[data-axis='horizontal'] {
      border-block: var(--moduix-image-cropper-grid-width, var(--moduix-border-width-sm)) solid
        var(--moduix-image-cropper-grid-color, rgb(255 255 255 / 62%));
    }

    &[data-axis='vertical'] {
      border-inline: var(--moduix-image-cropper-grid-width, var(--moduix-border-width-sm)) solid
        var(--moduix-image-cropper-grid-color, rgb(255 255 255 / 62%));
    }
  }

  .handle {
    position: absolute;
    z-index: 1;
    box-sizing: border-box;
    width: var(--moduix-image-cropper-handle-size, var(--moduix-spacing-3));
    height: var(--moduix-image-cropper-handle-size, var(--moduix-spacing-3));
    border: var(--moduix-image-cropper-handle-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-image-cropper-handle-border-color, rgb(255 255 255 / 88%));
    border-radius: var(--moduix-image-cropper-handle-radius, var(--moduix-radius-xs));
    background-color: var(--moduix-image-cropper-handle-bg, rgb(255 255 255 / 96%));
    box-shadow: var(--moduix-image-cropper-handle-shadow, 0 1px 3px rgb(15 23 42 / 18%));
    transition:
      border-color var(--moduix-image-cropper-transition, var(--moduix-transition-default)),
      background-color var(--moduix-image-cropper-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-image-cropper-transition, var(--moduix-transition-default)),
      opacity var(--moduix-image-cropper-transition, var(--moduix-transition-default));

    &[data-position='n'],
    &[data-position='s'] {
      width: 100% !important;
      height: var(--moduix-image-cropper-handle-edge-thickness, 0.2rem);
      border-width: 0;
      border-radius: var(--moduix-image-cropper-handle-edge-radius, var(--moduix-radius-full));
    }

    &[data-position='e'],
    &[data-position='w'] {
      width: var(--moduix-image-cropper-handle-edge-thickness, 0.2rem);
      height: 100% !important;
      border-width: 0;
      border-radius: var(--moduix-image-cropper-handle-edge-radius, var(--moduix-radius-full));
    }

    &[data-disabled] {
      display: none;
    }
  }
}
